"use client";

import { type RefObject, useState } from "react";
import { containsActiveElement } from "./focusable";
import {
  getFocusedNavigationValue,
  getNavigationItems,
} from "./navigation-items";
import type { NavigationRole, UseNavigationOptions } from "../use-navigation";

export type UseNavigationCoreOptions<TValue extends string = string> = Omit<
  UseNavigationOptions<TValue>,
  "enabled" | "preventDefault" | "orientation" | "upKeys" | "downKeys"
>;

export interface UseNavigationCoreReturn<TValue extends string = string> {
  highlighted: TValue | null;
  isHighlighted: (value: TValue) => boolean;
  highlight: (value: TValue | null) => void;
  move: (delta: 1 | -1, event?: globalThis.KeyboardEvent, key?: string) => void;
  focusIndex: (index: number) => boolean;
  handleSelect: (event: globalThis.KeyboardEvent) => void;
  handleEnter: (event: globalThis.KeyboardEvent) => void;
  getElements: () => HTMLElement[];
}

export function queryNavigationElements(
  containerRef: RefObject<HTMLElement | null>,
  role: NavigationRole,
  skipDisabled: boolean,
  scopeToContainer: boolean,
  ownerSelector: string | null | undefined,
): HTMLElement[] {
  return getNavigationItems(containerRef.current, {
    type: role,
    skipDisabled,
    scopeToContainer,
    ownerSelector,
  });
}

export function wrapIndex(index: number, length: number, wrap: boolean): number | null {
  if (index < 0) return wrap ? length - 1 : null;
  if (index >= length) return wrap ? 0 : null;
  return index;
}

/**
 * Shared list-navigation state machine used by the standalone and provider-backed
 * navigation hooks.
 */
export function useNavigationCore<TValue extends string = string>({
  containerRef,
  role,
  highlighted: controlledHighlighted,
  defaultHighlighted = null,
  onSelect,
  onEnter,
  onHighlightChange,
  wrap = true,
  onNavigationBoundaryReached,
  skipDisabled = true,
  moveFocus = false,
  scopeToContainer = true,
  ownerSelector,
}: UseNavigationCoreOptions<TValue>): UseNavigationCoreReturn<TValue> {
  const [internalHighlighted, setInternalHighlighted] = useState<TValue | null>(defaultHighlighted);
  const isControlled = controlledHighlighted !== undefined;
  const highlighted = isControlled ? (controlledHighlighted ?? null) : internalHighlighted;

  const setFocusedValue = (nextValue: TValue | null) => {
    if (!isControlled) setInternalHighlighted(nextValue);
    onHighlightChange?.(nextValue);
  };

  const getElements = () =>
    queryNavigationElements(containerRef, role, skipDisabled, scopeToContainer, ownerSelector);

  const getFocusedIndex = (): number => {
    const elements = getElements();
    if (elements.length === 0) return -1;

    const focusedIndex = elements.findIndex(containsActiveElement);
    if (focusedIndex >= 0) return focusedIndex;

    if (highlighted !== null) {
      const index = elements.findIndex((el) => el.dataset.value === highlighted);
      if (index >= 0) return index;
    }

    return -1;
  };

  const getCurrentValue = (): TValue | null => {
    const focusedValue = getFocusedNavigationValue(containerRef.current, {
      type: role,
      skipDisabled,
      scopeToContainer,
      ownerSelector,
    });
    // DOM boundary: data-value is opaque to TS; consumers parameterize TValue.
    if (focusedValue !== null) return focusedValue as TValue;

    const elements = getElements();

    if (highlighted !== null) {
      return elements.some((el) => el.dataset.value === highlighted) ? highlighted : null;
    }

    return null;
  };

  const focusIndex = (index: number, knownElements?: HTMLElement[]): boolean => {
    const elements = knownElements ?? getElements();
    const el = elements[index];
    if (!el) return false;
    const nextValue = el.dataset.value;
    if (nextValue === undefined) return false;

    el.scrollIntoView?.({ block: "nearest" });
    if (moveFocus) {
      el.focus();
      // Native disabled controls can't take DOM focus; report failure to step past.
      if (!containsActiveElement(el)) return false;
    }
    // DOM boundary: data-value is opaque to TS; consumers parameterize TValue.
    setFocusedValue(nextValue as TValue);
    return true;
  };

  const move = (delta: 1 | -1, event?: globalThis.KeyboardEvent, key?: string) => {
    const elements = getElements();
    if (elements.length === 0) return;

    const current = getFocusedIndex();
    let rawNext = current + delta;
    // Bounded by item count so an all-disabled wrap list can't loop forever.
    for (let attempts = 0; attempts < elements.length; attempts += 1) {
      const next = wrapIndex(rawNext, elements.length, wrap);
      if (next === null) {
        const direction = delta < 0 ? "previous" : "next";
        if (event && key) onNavigationBoundaryReached?.(direction, event, key);
        return;
      }
      if (next === current) return;
      if (focusIndex(next, elements)) return;
      if (!moveFocus) return;
      rawNext = next + delta;
    }
  };

  const handleSelect = (event: globalThis.KeyboardEvent) => {
    const currentValue = getCurrentValue();
    if (currentValue !== null) onSelect?.(currentValue, event);
  };

  const handleEnter = (event: globalThis.KeyboardEvent) => {
    const currentValue = getCurrentValue();
    if (currentValue === null) return;
    if (onEnter) onEnter(currentValue, event);
    else onSelect?.(currentValue, event);
  };

  const isHighlighted = (v: TValue) => highlighted === v;
  const highlight = (v: TValue | null) => setFocusedValue(v);

  return {
    highlighted,
    isHighlighted,
    highlight,
    move,
    focusIndex,
    handleSelect,
    handleEnter,
    getElements,
  };
}

const VERTICAL_UP_KEYS = ["ArrowUp"] as const;
const VERTICAL_DOWN_KEYS = ["ArrowDown"] as const;
const HORIZONTAL_UP_KEYS = ["ArrowLeft"] as const;
const HORIZONTAL_DOWN_KEYS = ["ArrowRight"] as const;

/** Resolves default previous/next keys for a vertical or horizontal list. */
export function resolveDirectionKeys(
  orientation: "vertical" | "horizontal",
  upKeys?: readonly string[],
  downKeys?: readonly string[],
): { resolvedUpKeys: readonly string[]; resolvedDownKeys: readonly string[] } {
  return {
    resolvedUpKeys: upKeys ?? (orientation === "vertical" ? VERTICAL_UP_KEYS : HORIZONTAL_UP_KEYS),
    resolvedDownKeys:
      downKeys ?? (orientation === "vertical" ? VERTICAL_DOWN_KEYS : HORIZONTAL_DOWN_KEYS),
  };
}

/**
 * Dispatches one navigation key to movement, edge, and activation callbacks.
 * Returns whether the key was handled.
 */
export function dispatchNavigationKey(
  key: string,
  ctx: {
    resolvedUpKeys: readonly string[];
    resolvedDownKeys: readonly string[];
    move: (dir: 1 | -1) => void;
    focusIndex: (index: number) => boolean;
    handleSelect?: (event: globalThis.KeyboardEvent) => void;
    handleEnter?: (event: globalThis.KeyboardEvent) => void;
    total: number;
    nativeEvent: globalThis.KeyboardEvent;
  },
): boolean {
  if (ctx.resolvedUpKeys.includes(key)) {
    ctx.move(-1);
    return true;
  }

  if (ctx.resolvedDownKeys.includes(key)) {
    ctx.move(1);
    return true;
  }

  switch (key) {
    case "Home":
      // Step forward so a native-disabled first item is skipped, matching arrow stepping.
      for (let index = 0; index < ctx.total; index += 1) {
        if (ctx.focusIndex(index)) break;
      }
      return true;
    case "End":
      for (let index = ctx.total - 1; index >= 0; index -= 1) {
        if (ctx.focusIndex(index)) break;
      }
      return true;
    case "Enter":
      if (!ctx.handleEnter) return false;
      ctx.handleEnter(ctx.nativeEvent);
      return true;
    case " ":
      if (!ctx.handleSelect) return false;
      ctx.handleSelect(ctx.nativeEvent);
      return true;
  }

  return false;
}

import { composedClosest } from "./element-guards";
import { containsActiveElement, documentOrder, isReachable } from "./focusable";

/** Data attribute used by @diffgazer/keys to mark navigable DOM items. */
export const NAVIGATION_ITEM_ATTRIBUTE = "data-diffgazer-navigation-item";

/** Navigation item types recognized by DOM query helpers and navigation hooks. */
export type NavigationItemType =
  | "radio"
  | "checkbox"
  | "option"
  | "menuitem"
  | "menuitemcheckbox"
  | "menuitemradio"
  | "button"
  | "tab";

/** Query used to discover navigable items inside a container. */
export interface NavigationItemQuery {
  /** Item role or data-contract type to query. */
  type: NavigationItemType;
  /**
   * Exclude items that expose or inherit a disabled state: aria-disabled,
   * data-disabled, or native disabled on the item or an ancestor.
   */
  skipDisabled?: boolean;
  /** Exclude items owned by nested composite containers. */
  scopeToContainer?: boolean;
  /** Override the composite owner selector used for scoping, or null to disable owner scoping. */
  ownerSelector?: string | null;
}

function disabledSelector(skipDisabled: boolean): string {
  return skipDisabled ? ':not([aria-disabled="true"]):not([data-disabled]):not(:disabled)' : "";
}

/** True when an aria-disabled/data-disabled ancestor (not the element itself) disables the item. */
function hasDisabledAncestor(element: HTMLElement): boolean {
  const disabledContainer = composedClosest(element, '[aria-disabled="true"],[data-disabled]');
  return disabledContainer !== null && disabledContainer !== element;
}

function findElements(container: HTMLElement, selector: string): HTMLElement[] {
  return Array.from(container.querySelectorAll<HTMLElement>(selector));
}

function queryAllMatchingGroups(
  container: HTMLElement,
  selectors: string[],
  filter?: (element: HTMLElement) => boolean,
): HTMLElement[] {
  const seen = new Set<HTMLElement>();
  const merged: HTMLElement[] = [];

  for (const selector of selectors) {
    const elements = findElements(container, selector);
    for (const el of elements) {
      if (seen.has(el)) continue;
      if (filter && !filter(el)) continue;
      seen.add(el);
      merged.push(el);
    }
  }

  // Merged results from multiple selectors may interleave; restore DOM order.
  if (merged.length > 1) {
    merged.sort(documentOrder);
  }

  return merged;
}

function matchesNavigationDataContract(element: HTMLElement, type: NavigationItemType): boolean {
  const explicitType = element.getAttribute(NAVIGATION_ITEM_ATTRIBUTE);
  return (
    explicitType === null || explicitType === "" || explicitType === "true" || explicitType === type
  );
}

function buildNavigationSelectors(type: NavigationItemType, skipDisabled: boolean): string[] {
  const disabled = disabledSelector(skipDisabled);
  const nativeRoleSelectors: Partial<Record<NavigationItemType, string[]>> = {
    button: [`button[data-value]${disabled}`],
    checkbox: [`input[type="checkbox"][data-value]${disabled}`],
    radio: [`input[type="radio"][data-value]${disabled}`],
  };

  return [
    `[${NAVIGATION_ITEM_ATTRIBUTE}][data-value]${disabled}`,
    `[role="${type}"][data-value]${disabled}`,
    ...(nativeRoleSelectors[type] ?? []),
  ];
}

function ownerSelectorForType(type: NavigationItemType): string | null {
  switch (type) {
    case "radio":
      return '[role="radiogroup"]';
    case "checkbox":
      return '[role="group"]';
    case "option":
      return '[role="listbox"]';
    case "menuitem":
    case "menuitemcheckbox":
    case "menuitemradio":
      return '[role="menu"]';
    case "tab":
      return '[role="tablist"]';
    case "button":
      return null;
  }
}

function isOwnedByContainer(
  element: HTMLElement,
  container: HTMLElement,
  query: NavigationItemQuery,
): boolean {
  if (query.scopeToContainer === false) return true;

  if (query.ownerSelector !== undefined) {
    if (query.ownerSelector === null) return true;
    const owner = element.closest(query.ownerSelector);
    return owner === null || owner === container;
  }

  const ownerSelector = ownerSelectorForType(query.type);
  if (!ownerSelector) return true;

  const owner = element.closest(ownerSelector);
  return owner === null || owner === container;
}

/**
 * Finds navigable descendants matching the role/data contract in DOM order.
 * Items hidden by `hidden`, `inert`, or `aria-hidden="true"` (self or ancestor,
 * across shadow boundaries) are always excluded because they are not
 * accessibility-reachable. Disabled items and items under an
 * aria-disabled/data-disabled ancestor are skipped by default.
 */
export function getNavigationItems(
  container: HTMLElement | null,
  query: NavigationItemQuery,
): HTMLElement[] {
  if (!container) return [];

  const skipDisabled = query.skipDisabled ?? true;

  return queryAllMatchingGroups(
    container,
    buildNavigationSelectors(query.type, skipDisabled),
    (element) =>
      matchesNavigationDataContract(element, query.type) &&
      isOwnedByContainer(element, container, query) &&
      isReachable(element) &&
      (!skipDisabled || !hasDisabledAncestor(element)),
  );
}

/** Finds one navigable item by its `data-value`. */
export function findNavigationItemByValue(
  container: HTMLElement | null,
  query: NavigationItemQuery & { value: string },
): HTMLElement | null {
  return (
    getNavigationItems(container, query).find((element) => element.dataset.value === query.value) ??
    null
  );
}

/** Returns the public data attributes needed for role-independent navigation. */
export function getNavigationItemProps(
  type: NavigationItemType,
  value: string,
): {
  "data-diffgazer-navigation-item": NavigationItemType;
  "data-value": string;
} {
  return {
    [NAVIGATION_ITEM_ATTRIBUTE]: type,
    "data-value": value,
  };
}

/** Returns the `data-value` for the navigable item containing DOM focus. */
export function getFocusedNavigationValue(
  container: HTMLElement | null,
  query: NavigationItemQuery,
): string | null {
  const focusedItem = getNavigationItems(container, query).find(containsActiveElement);
  return focusedItem?.dataset.value ?? null;
}

/**
 * Moves DOM focus to a navigable item by value, with optional first/last
 * fallback, and returns the focused value.
 */
export function focusNavigationItem(
  container: HTMLElement | null,
  query: NavigationItemQuery & {
    value: string;
    fallback?: "first" | "last" | "none";
    preventScroll?: boolean;
  },
): string | null {
  const items = getNavigationItems(container, query);
  const target =
    items.find((element) => element.dataset.value === query.value) ??
    (query.fallback === "first" ? items[0] : undefined) ??
    (query.fallback === "last" ? items.at(-1) : undefined) ??
    null;

  if (!target || target.dataset.value === undefined) return null;

  target.focus({ preventScroll: query.preventScroll });
  return target.dataset.value;
}

/** Vertical movement direction derived from ArrowUp/ArrowDown or boundaries. */
export type VerticalDirection = "up" | "down";

/** Orientation-neutral boundary direction emitted by navigation hooks. */
export type BoundaryDirection = "previous" | "next";

const LIST_NAVIGATION_KEYS = new Set(["ArrowUp", "ArrowDown", "Home", "End", "Enter", " "]);

/** Returns true for keys handled by the list-navigation primitives. */
export function isListNavigationKey(key: string): boolean {
  return LIST_NAVIGATION_KEYS.has(key);
}

/** Maps ArrowUp/ArrowDown to a semantic vertical direction. */
export function getVerticalArrowDirection(key: string): VerticalDirection | null {
  if (key === "ArrowUp") return "up";
  if (key === "ArrowDown") return "down";
  return null;
}

/** Converts a previous/next boundary to up/down. */
export function toVerticalBoundaryDirection(direction: BoundaryDirection): VerticalDirection;
/** Converts a boundary to up/down only when the triggering key was vertical. */
export function toVerticalBoundaryDirection(
  direction: BoundaryDirection,
  key: string,
): VerticalDirection | null;
/** Implementation for boundary-to-vertical direction mapping. */
export function toVerticalBoundaryDirection(
  direction: BoundaryDirection,
  key?: string,
): VerticalDirection | null {
  if (key !== undefined && getVerticalArrowDirection(key) === null) return null;
  return direction === "previous" ? "up" : "down";
}

import {
  composedClosest,
  composedContains,
  getDeepActiveElement,
  getShadowHost,
  isHTMLElement,
  isHTMLInputElement,
} from "./element-guards";

const FOCUSABLE_SELECTOR = [
  "a[href]",
  "area[href]",
  "button:not([disabled])",
  'input:not([type="hidden"]):not([disabled])',
  "select:not([disabled])",
  "textarea:not([disabled])",
  "iframe",
  "object",
  "embed",
  "audio[controls]",
  "video[controls]",
  '[contenteditable]:not([contenteditable="false"])',
  "details > summary:first-of-type",
  "[tabindex]:not([disabled])",
].join(",");

function getComposedParentElement(element: Element): Element | null {
  return element.assignedSlot ?? element.parentElement ?? getShadowHost(element);
}

export function getComposedChildren(element: Element): Element[] {
  if (element.shadowRoot) return Array.from(element.shadowRoot.children);
  if (element.localName === "slot") {
    const assigned = (element as HTMLSlotElement).assignedElements({ flatten: true });
    if (assigned.length > 0) return assigned;
  }
  return Array.from(element.children);
}

function isHidden(element: HTMLElement): boolean {
  const elementVisibility = element.ownerDocument.defaultView?.getComputedStyle(element).visibility;
  if (elementVisibility === "hidden" || elementVisibility === "collapse") return true;

  let current: Element | null = element;
  while (current) {
    const style = current.ownerDocument.defaultView?.getComputedStyle(current);
    // area is display:none by default in every UA stylesheet yet remains
    // focusable via its own href; only its ancestors' display can hide it.
    const isOwnAreaDisplayNone = current === element && current.localName === "area";
    if (
      current.getAttribute("hidden") === "until-found" ||
      (!isOwnAreaDisplayNone && style?.display === "none") ||
      style?.getPropertyValue("content-visibility") === "hidden"
    ) {
      return true;
    }
    current = getComposedParentElement(current);
  }
  return false;
}

function isInert(element: HTMLElement): boolean {
  return composedClosest(element, "[inert]") !== null;
}

function isAriaHidden(element: HTMLElement): boolean {
  // Per ARIA, aria-hidden="false" does NOT re-expose content hidden by an aria-hidden="true" ancestor.
  return composedClosest(element, '[aria-hidden="true"]') !== null;
}

function isHiddenByClosedDetails(element: HTMLElement): boolean {
  let current = getComposedParentElement(element);

  while (current) {
    if (current.localName === "details" && !current.hasAttribute("open")) {
      const firstSummary = Array.from(current.children).find(
        (child) => child.localName === "summary",
      );
      if (!firstSummary || !composedContains(firstSummary, element)) return true;
    }
    current = getComposedParentElement(current);
  }

  return false;
}

/**
 * Returns false when a hidden, inert, or aria-hidden="true" self-or-ancestor
 * (across shadow boundaries) removes the element from keyboard reach. Shared
 * with navigation discovery so it skips the same unreachable items focus does.
 */
export function isReachable(element: HTMLElement): boolean {
  return (
    !isHidden(element) &&
    !isInert(element) &&
    !isAriaHidden(element) &&
    !isHiddenByClosedDetails(element)
  );
}

export function isInsideDisabledFieldset(element: HTMLElement): boolean {
  let fieldset = element.closest<HTMLFieldSetElement>("fieldset[disabled]");
  while (fieldset) {
    const legend = fieldset.querySelector(":scope > legend");
    if (legend?.contains(element)) {
      // Descendants of the first <legend> are not disabled per spec; keep searching upward.
      fieldset = fieldset.parentElement?.closest<HTMLFieldSetElement>("fieldset[disabled]") ?? null;
      continue;
    }
    return true;
  }
  return false;
}

/**
 * Returns true for visible, non-disabled elements that can receive programmatic
 * focus, including `tabIndex={-1}` targets.
 */
export function isFocusable(element: HTMLElement | null): boolean {
  if (!isHTMLElement(element)) return false;
  if (!element.matches(FOCUSABLE_SELECTOR)) return false;
  if (!isReachable(element)) return false;
  if (isInsideDisabledFieldset(element)) return false;
  return true;
}

// jsdom returns compound-selector matches out of tree order; normalize.
const DOCUMENT_POSITION_PRECEDING = 0x02;
const DOCUMENT_POSITION_FOLLOWING = 0x04;

function nativeDocumentOrder(a: HTMLElement, b: HTMLElement): number {
  const pos = a.compareDocumentPosition(b);
  if (pos & DOCUMENT_POSITION_FOLLOWING) return -1;
  if (pos & DOCUMENT_POSITION_PRECEDING) return 1;
  return 0;
}

function composedPath(element: HTMLElement): Element[] {
  const path: Element[] = [];
  let current: Element | null = element;
  while (current) {
    path.push(current);
    current = getComposedParentElement(current);
  }
  return path.reverse();
}

/** Sort comparator that returns elements in composed order across open shadow roots. */
export function documentOrder(a: HTMLElement, b: HTMLElement): number {
  if (a === b) return 0;

  const aPath = composedPath(a);
  const bPath = composedPath(b);
  let index = 0;
  while (aPath[index] && aPath[index] === bPath[index]) index += 1;

  if (index === 0) return nativeDocumentOrder(a, b);
  if (index === aPath.length) return -1;
  if (index === bPath.length) return 1;

  const parent = aPath[index - 1];
  const aSibling = aPath[index];
  const bSibling = bPath[index];
  if (!parent || !aSibling || !bSibling) return nativeDocumentOrder(a, b);

  const children = getComposedChildren(parent);
  const aIndex = children.indexOf(aSibling);
  const bIndex = children.indexOf(bSibling);
  return aIndex >= 0 && bIndex >= 0 ? aIndex - bIndex : nativeDocumentOrder(a, b);
}

function getComposedDescendants(container: HTMLElement): HTMLElement[] {
  const matches: HTMLElement[] = [];
  const visit = (element: Element) => {
    if (
      isHTMLElement(element) &&
      element.matches(FOCUSABLE_SELECTOR) &&
      !element.shadowRoot?.delegatesFocus
    ) {
      matches.push(element);
    }
    for (const child of getComposedChildren(element)) visit(child);
  };

  for (const child of getComposedChildren(container)) visit(child);
  return matches;
}

/**
 * Returns all focusable descendants in DOM order, including programmatic focus
 * targets that are not reachable by Tab.
 */
export function getFocusableElements(container: HTMLElement | null): HTMLElement[] {
  if (!container) return [];
  return getComposedDescendants(container).filter((element) => isFocusable(element));
}

function isRadioInput(element: HTMLElement): element is HTMLInputElement {
  return isHTMLInputElement(element) && element.type === "radio";
}

function isRadioGroupTabStop(element: HTMLElement, focusableElements: HTMLElement[]): boolean {
  if (!isRadioInput(element) || element.name === "") return true;
  const root = element.getRootNode();

  const group = focusableElements.filter(
    (candidate) =>
      isRadioInput(candidate) &&
      candidate.name === element.name &&
      candidate.form === element.form &&
      candidate.getRootNode() === root,
  );
  const checked = group.find((candidate) => isRadioInput(candidate) && candidate.checked);
  return element === (checked ?? group[0]);
}

function tabIndexOrder(element: HTMLElement): number {
  return element.tabIndex > 0 ? element.tabIndex : Number.MAX_SAFE_INTEGER;
}

/**
 * Returns browser Tab-order descendants, excluding negative tabindex targets
 * and collapsing native radio groups to one Tab stop.
 */
export function getTabbableElements(container: HTMLElement | null): HTMLElement[] {
  if (!container) return [];
  const focusableElements = getFocusableElements(container).filter(
    (element) => element.tabIndex >= 0,
  );
  return focusableElements
    .map((element, index) => ({ element, index }))
    .filter(({ element }) => isRadioGroupTabStop(element, focusableElements))
    .sort((a, b) => tabIndexOrder(a.element) - tabIndexOrder(b.element) || a.index - b.index)
    .map(({ element }) => element);
}

/** Returns the first focusable descendant in DOM order. */
export function getFirstFocusableElement(container: HTMLElement | null): HTMLElement | null {
  return getFocusableElements(container)[0] ?? null;
}

/** Returns true when the element contains its owner document's deep active element, across shadow roots. */
export function containsActiveElement(element: HTMLElement): boolean {
  const activeElement = getDeepActiveElement(element.ownerDocument);
  return isHTMLElement(activeElement) && composedContains(element, activeElement);
}

/** Returns the `Window` realm for a DOM value, or null for non-DOM values. */
export function getOwnerView(value: unknown): (Window & typeof globalThis) | null {
  const element = value as { ownerDocument?: Document } | null;
  return element?.ownerDocument?.defaultView ?? null;
}

/** Realm-safe HTMLElement guard for elements from iframes or other documents. */
export function isHTMLElement(value: unknown): value is HTMLElement {
  const View = getOwnerView(value);
  return Boolean(View && value instanceof View.HTMLElement);
}

/** Realm-safe HTMLInputElement guard. */
export function isHTMLInputElement(value: unknown): value is HTMLInputElement {
  const View = getOwnerView(value);
  return Boolean(View && value instanceof View.HTMLInputElement);
}

/** Realm-safe HTMLTextAreaElement guard. */
export function isHTMLTextAreaElement(value: unknown): value is HTMLTextAreaElement {
  const View = getOwnerView(value);
  return Boolean(View && value instanceof View.HTMLTextAreaElement);
}

/** Realm-safe Node guard using a known owner window. */
export function isNode(
  value: unknown,
  ownerView: (Window & typeof globalThis) | null,
): value is Node {
  return Boolean(ownerView && value instanceof ownerView.Node);
}

/** Returns the shadow host when a node lives in a shadow root, else null. */
export function getShadowHost(node: Node): Element | null {
  const view = getOwnerView(node);
  const root = node.getRootNode();
  return view && root instanceof view.ShadowRoot ? root.host : null;
}

/** Returns the deepest active element, descending through open shadow roots. */
export function getDeepActiveElement(root: Document | ShadowRoot): Element | null {
  let active = root.activeElement;
  while (active?.shadowRoot?.activeElement) {
    active = active.shadowRoot.activeElement;
  }
  return active;
}

/** Returns true when `container` contains `target` in the composed tree, across shadow boundaries. */
export function composedContains(container: Node, target: Node | null): boolean {
  let node: Node | null = target;
  while (node) {
    if (container.contains(node)) return true;
    node = getShadowHost(node);
  }
  return false;
}

/** Returns the nearest self-or-ancestor matching `selector` in the composed tree, across shadow boundaries. */
export function composedClosest(element: Element, selector: string): Element | null {
  let current: Element | null = element;
  while (current) {
    const match = current.closest(selector);
    if (match) return match;
    current = getShadowHost(current);
  }
  return null;
}

/**
 * Returns the deepest composed event target, past the retargeted shadow host.
 * Empty `composedPath()` (before dispatch) falls back to `event.target`.
 */
export function getComposedEventTarget(event: Event): EventTarget | null {
  return event.composedPath()[0] ?? event.target;
}

/**
 * Returns true for form-like or editable elements that can own keyboard input,
 * including select and non-text input types.
 */
export function isInputElement(target: EventTarget | null): boolean {
  if (!isHTMLElement(target)) return false;
  const tag = target.tagName.toLowerCase();
  return Boolean(
    tag === "input" || tag === "textarea" || tag === "select" || target.isContentEditable,
  );
}

const NON_EDITABLE_INPUT_TYPES = new Set([
  "button",
  "checkbox",
  "color",
  "file",
  "hidden",
  "image",
  "radio",
  "range",
  "reset",
  "submit",
]);

function hasContentEditableAttribute(element: HTMLElement): boolean {
  if (element.isContentEditable) return true;
  const value = element.getAttribute("contenteditable");
  if (value === null) return false;
  return value === "" || value === "true" || value === "plaintext-only";
}

/**
 * Returns true only for enabled text-editable targets that should keep typing
 * keys instead of global shortcuts.
 */
export function isEditableElement(target: EventTarget | null): boolean {
  if (!isHTMLElement(target)) return false;

  if (isHTMLTextAreaElement(target)) {
    return !target.disabled && !target.readOnly;
  }

  if (isHTMLInputElement(target)) {
    if (target.disabled || target.readOnly) return false;
    const type = (target.type || "text").toLowerCase();
    return !NON_EDITABLE_INPUT_TYPES.has(type);
  }

  return hasContentEditableAttribute(target);
}

